import { useState } from "react";
import { useTranslation } from "react-i18next";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { AlertTriangle, Trash2 } from "lucide-react";

interface DeleteUserDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  userName: string;
  userId: string;
  userRole: string;
  onConfirm: () => void;
  isDeleting?: boolean;
}

const DeleteUserDialog = ({
  open,
  onOpenChange,
  userName,
  userId,
  userRole,
  onConfirm,
  isDeleting = false,
}: DeleteUserDialogProps) => {
  const { t } = useTranslation();
  const [step, setStep] = useState<1 | 2>(1);
  const [confirmText, setConfirmText] = useState("");

  const handleClose = () => {
    setStep(1);
    setConfirmText("");
    onOpenChange(false);
  };

  const handleFirstConfirm = () => {
    setStep(2);
  };

  const handleFinalConfirm = () => {
    if (confirmText.toLowerCase() === "delete") {
      onConfirm();
      // Don't call handleClose() here - let parent control dialog state after async operation
    }
  };

  return (
    <AlertDialog open={open} onOpenChange={(isOpen) => {
      if (!isOpen) {
        handleClose();
      } else {
        onOpenChange(isOpen);
      }
    }}>
      <AlertDialogContent className="max-w-[90vw] sm:max-w-[500px]">
        {step === 1 ? (
          <>
            <AlertDialogHeader>
              <AlertDialogTitle className="flex items-center gap-2 text-destructive">
                <AlertTriangle className="h-5 w-5" />
                {t("admin.deleteUser")}
              </AlertDialogTitle>
              <AlertDialogDescription className="space-y-4 pt-4">
                <div className="bg-destructive/10 border border-destructive/20 p-4 rounded-lg">
                  <p className="font-semibold text-foreground mb-2">
                    {t("admin.deleteUserWarning")}
                  </p>
                  <div className="space-y-2 text-sm">
                    <p><strong>{t("admin.userName")}:</strong> {userName}</p>
                    <p><strong>{t("admin.userRole")}:</strong> {userRole}</p>
                  </div>
                </div>
                
                <div className="space-y-2 text-sm text-muted-foreground">
                  <p>{t("admin.deleteUserConsequences")}</p>
                  <ul className="list-disc list-inside space-y-1 ml-2">
                    <li>{t("admin.deleteUserData1")}</li>
                    <li>{t("admin.deleteUserData2")}</li>
                    <li>{t("admin.deleteUserData3")}</li>
                    <li>{t("admin.deleteUserData4")}</li>
                  </ul>
                </div>

                {userRole === "admin" && (
                  <div className="bg-destructive/20 border border-destructive p-3 rounded-lg">
                    <p className="text-sm font-semibold text-destructive">
                      ⚠️ {t("admin.deleteAdminWarning")}
                    </p>
                  </div>
                )}
              </AlertDialogDescription>
            </AlertDialogHeader>
            <AlertDialogFooter>
              <AlertDialogCancel onClick={handleClose}>
                {t("common.cancel")}
              </AlertDialogCancel>
              <AlertDialogAction
                onClick={handleFirstConfirm}
                className="bg-destructive hover:bg-destructive/90"
              >
                {t("common.continue")}
              </AlertDialogAction>
            </AlertDialogFooter>
          </>
        ) : (
          <>
            <AlertDialogHeader>
              <AlertDialogTitle className="flex items-center gap-2 text-destructive">
                <Trash2 className="h-5 w-5" />
                {t("admin.confirmDeleteUser")}
              </AlertDialogTitle>
              <AlertDialogDescription className="space-y-4 pt-4">
                <p className="text-foreground font-medium">
                  {t("admin.finalDeleteWarning", { userName })}
                </p>
                
                <div className="space-y-2">
                  <Label htmlFor="delete-confirm" className="text-sm font-medium">
                    {t("admin.typeDeleteToConfirm")}
                  </Label>
                  <Input
                    id="delete-confirm"
                    value={confirmText}
                    onChange={(e) => setConfirmText(e.target.value)}
                    placeholder="DELETE"
                    className="uppercase"
                    autoComplete="off"
                  />
                </div>
              </AlertDialogDescription>
            </AlertDialogHeader>
            <AlertDialogFooter>
              <AlertDialogCancel onClick={handleClose}>
                {t("common.cancel")}
              </AlertDialogCancel>
              <AlertDialogAction
                onClick={handleFinalConfirm}
                disabled={confirmText.toLowerCase() !== "delete" || isDeleting}
                className="bg-destructive hover:bg-destructive/90"
              >
                {isDeleting ? t("common.loading") : t("admin.deleteUser")}
              </AlertDialogAction>
            </AlertDialogFooter>
          </>
        )}
      </AlertDialogContent>
    </AlertDialog>
  );
};

export default DeleteUserDialog;
