const PAGE_SIZE = 30;

interface AdminUser {
  id: string;
  display_name: string;
  avatar_url: string | null;
  phone: string | null;
  points: number;
  is_banned: boolean;
  is_muted: boolean;
  merchant_type: string | null;
  created_at: string;
  vip_level: string | null;
  role: string;
  email?: string;
  last_sign_in_at?: string | null;
  auth_created_at?: string;
}

const useAdminUsersPaginated = (
  page: number,
  filters: {
    search: string;
    roleFilter: string;
    sortBy: string;
    sortDirection: string;
  }
) => {
  const { user } = useAuth();

  return useQuery({
    queryKey: ["admin-users-paginated", page, filters, user?.id],
    queryFn: async () => {
      if (!user) return { users: [], total: 0 };

      const { data, error } = await supabase.rpc("get_admin_users_paginated", {
        p_offset: page * PAGE_SIZE,
        p_limit: PAGE_SIZE,
        p_search: filters.search || null,
        p_role_filter: filters.roleFilter,
        p_sort_by: filters.sortBy,
        p_sort_direction: filters.sortDirection,
      });

      if (error) throw error;

      const result = data as any;
      if (result?.error) throw new Error(result.error);

      // Fetch emails for the current page of users via edge function
      const users = (result?.users || []) as AdminUser[];
      
      if (users.length > 0) {
        try {
          const session = await supabase.auth.getSession();
          if (session.data?.session?.access_token) {
            const response = await supabase.functions.invoke("get-user-emails", {
              headers: {
                Authorization: `Bearer ${session.data.session.access_token}`,
              },
            });
            if (response.data?.emails) {
              const emailMap = response.data.emails as Record<string, string>;
              const lastSignInMap = (response.data.lastSignIn || {}) as Record<string, string | null>;
              const createdAtMap = (response.data.createdAt || {}) as Record<string, string>;
              users.forEach(u => {
                u.email = emailMap[u.id] || "";
                u.last_sign_in_at = lastSignInMap[u.id] || null;
                u.auth_created_at = createdAtMap[u.id] || u.created_at;
              });
            }
          }
        } catch (e) {
          console.error("Failed to fetch user emails:", e);
        }
      }

      return {
        users,
        total: result?.total || 0,
      };
    },
    staleTime: 30000,
    placeholderData: (prev) => prev,
  });
};

// Stats query - lightweight, separate from paginated data
const useAdminUserStats = () => {
  const { user } = useAuth();
  return useQuery({
    queryKey: ["admin-user-stats", user?.id],
    queryFn: async () => {
      if (!user) return null;
      
      const { data, error } = await supabase.rpc("get_admin_users_paginated", {
        p_offset: 0,
        p_limit: 1,
        p_search: null,
        p_role_filter: "all",
        p_sort_by: "created",
        p_sort_direction: "desc",
      });
      if (error) throw error;
      const total = (data as any)?.total || 0;
      
      // Get role counts in parallel
      const [adminRes, supervisorRes, merchantRes, shallowRes, userRes] = await Promise.all([
        supabase.rpc("get_admin_users_paginated", { p_offset: 0, p_limit: 1, p_search: null, p_role_filter: "admin", p_sort_by: "created", p_sort_direction: "desc" }),
        supabase.rpc("get_admin_users_paginated", { p_offset: 0, p_limit: 1, p_search: null, p_role_filter: "supervisor", p_sort_by: "created", p_sort_direction: "desc" }),
        supabase.rpc("get_admin_users_paginated", { p_offset: 0, p_limit: 1, p_search: null, p_role_filter: "merchant", p_sort_by: "created", p_sort_direction: "desc" }),
        supabase.rpc("get_admin_users_paginated", { p_offset: 0, p_limit: 1, p_search: null, p_role_filter: "shallow_merchant", p_sort_by: "created", p_sort_direction: "desc" }),
        supabase.rpc("get_admin_users_paginated", { p_offset: 0, p_limit: 1, p_search: null, p_role_filter: "user", p_sort_by: "created", p_sort_direction: "desc" }),
      ]);

      return {
        total,
        admins: (adminRes.data as any)?.total || 0,
        supervisors: (supervisorRes.data as any)?.total || 0,
        merchants: (merchantRes.data as any)?.total || 0,
        shallowMerchants: (shallowRes.data as any)?.total || 0,
        regularUsers: (userRes.data as any)?.total || 0,
      };
    },
    staleTime: 60000,
  });
};

const AdminUsers = () => {
  const { t } = useTranslation();
  const { toast } = useToast();
  const navigate = useNavigate();
  const queryClient = useQueryClient();
  const { isSupervisor, isAdmin } = useUserRole();
  const changeRole = useChangeRole();
  const batchDeleteUsers = useBatchDeleteUsers();
  const batchChangeRole = useBatchChangeRole();
  const deleteUser = useDeleteUser();

  const [currentPage, setCurrentPage] = useState(0);
  const [searchInput, setSearchInput] = useState("");
  const [debouncedSearch, setDebouncedSearch] = useState("");
  const [roleFilter, setRoleFilter] = useState("all");
  const [sortBy, setSortBy] = useState<string>("created");
  const [sortDirection, setSortDirection] = useState<string>("desc");
  const [selectedUsers, setSelectedUsers] = useState<string[]>([]);
  const [batchRole, setBatchRole] = useState<string>("user");

  // Dialog states
  const [deleteUserDialog, setDeleteUserDialog] = useState({ open: false, userId: "", userName: "", userRole: "" });
  const [batchDeleteDialog, setBatchDeleteDialog] = useState({ open: false, step: 1 as 1 | 2, confirmText: "" });
  const [roleChangeDialog, setRoleChangeDialog] = useState({ open: false, userId: "", userName: "", currentRole: "", newRole: "" });
  const [merchantRestaurantsDialog, setMerchantRestaurantsDialog] = useState({ open: false, merchantId: "", merchantName: "", userRole: "merchant" as "merchant" | "supervisor" });
  const [userProfileDialog, setUserProfileDialog] = useState({ open: false, userId: "", userName: "", userRole: "" });

  // Debounce search
  useEffect(() => {
    const timer = setTimeout(() => {
      setDebouncedSearch(searchInput);
      setCurrentPage(0);
    }, 400);
    return () => clearTimeout(timer);
  }, [searchInput]);

  const filters = useMemo(() => ({
    search: debouncedSearch,
    roleFilter,
    sortBy,
    sortDirection,
  }), [debouncedSearch, roleFilter, sortBy, sortDirection]);

  const { data, isLoading } = useAdminUsersPaginated(currentPage, filters);
  const { data: stats } = useAdminUserStats();

  const users = data?.users || [];
  const totalItems = data?.total || 0;
  const totalPages = Math.ceil(totalItems / PAGE_SIZE);
  const startIndex = currentPage * PAGE_SIZE + 1;
  const endIndex = Math.min((currentPage + 1) * PAGE_SIZE, totalItems);

  const allRoles = ["user", "merchant", "shallow_merchant", "supervisor", "admin"];
  const availableRoles = isSupervisor
    ? allRoles.filter(role => role === "user" || role === "merchant" || role === "shallow_merchant")
    : allRoles;

  const goToPage = useCallback((page: number) => {
    if (page >= 0 && page < totalPages) setCurrentPage(page);
  }, [totalPages]);

  const toggleSelectUser = (userId: string) => {
    setSelectedUsers(prev => prev.includes(userId) ? prev.filter(id => id !== userId) : [...prev, userId]);
  };

  const toggleSelectAll = () => {
    if (selectedUsers.length === users.length && users.length > 0) {
      setSelectedUsers([]);
    } else {
      setSelectedUsers(users.map(u => u.id));
    }
  };

  const invalidateAll = () => {
    queryClient.invalidateQueries({ queryKey: ["admin-users-paginated"] });
    queryClient.invalidateQueries({ queryKey: ["admin-user-stats"] });
    queryClient.invalidateQueries({ queryKey: ["admin-users"] });
  };

  const handleDeleteUser = () => {
    if (!deleteUserDialog.userId) return;
    deleteUser.mutate(deleteUserDialog.userId, {
      onSettled: () => {
        setDeleteUserDialog({ open: false, userId: "", userName: "", userRole: "" });
        invalidateAll();
      },
    });
  };

  const handleBatchDeleteConfirm = () => {
    if (selectedUsers.length === 0 || batchDeleteDialog.confirmText.toLowerCase() !== "delete") return;
    batchDeleteUsers.mutate(selectedUsers, {
      onSuccess: () => {
        setSelectedUsers([]);
        setBatchDeleteDialog({ open: false, step: 1, confirmText: "" });
        invalidateAll();
      },
    });
  };

  const handleBatchChangeRole = () => {
    if (selectedUsers.length === 0) return;
    batchChangeRole.mutate(
      { userIds: selectedUsers, role: batchRole as any },
      {
        onSuccess: () => {
          setSelectedUsers([]);
          invalidateAll();
        },
      }
    );
  };

  const handleChangeRole = () => {
    if (roleChangeDialog.userId && roleChangeDialog.newRole) {
      const isShallowMerchant = roleChangeDialog.newRole === "shallow_merchant";
      const actualRole = isShallowMerchant ? "merchant" : roleChangeDialog.newRole;
      const merchantType = isShallowMerchant ? "shallow" : null;
      changeRole.mutate(
        { userId: roleChangeDialog.userId, role: actualRole as any, merchantType },
        {
          onSuccess: () => {
            setRoleChangeDialog({ open: false, userId: "", userName: "", currentRole: "", newRole: "" });
            invalidateAll();
          },
        }
      );
    }
  };

  const handleExport = async () => {
    // For export, we need the old useAdminUsers data - fetch all
    toast({ title: "导出中...", description: "正在准备数据" });
    try {
      const { data: allUsers } = await supabase.from("profiles").select("*").order("created_at", { ascending: false });
      if (allUsers && allUsers.length > 0) {
        exportUsersToCSV(allUsers as any);
        toast({ title: "导出成功" });
      }
    } catch {
      toast({ title: "导出失败", variant: "destructive" });
    }
  };

  const getRoleBadgeVariant = (role: string, merchantType?: string | null) => {
    if (role === "shallow_merchant" || (role === "merchant" && merchantType === "shallow")) {
      return "bg-cyan-500/10 text-cyan-700 border-cyan-200 dark:text-cyan-400 dark:border-cyan-800";
    }
    switch (role) {
      case "admin": return "bg-primary/10 text-primary border-primary/20";
      case "supervisor": return "bg-blue-500/10 text-blue-700 border-blue-200 dark:text-blue-400 dark:border-blue-800";
      case "merchant": return "bg-emerald-500/10 text-emerald-700 border-emerald-200 dark:text-emerald-400 dark:border-emerald-800";
      default: return "bg-muted text-muted-foreground border-border";
    }
  };

  const getRoleIcon = (role: string) => {
    switch (role) {
      case "admin": return <Shield className="h-3 w-3" />;
      case "supervisor": return <Shield className="h-3 w-3" />;
      case "merchant": return <Briefcase className="h-3 w-3" />;
      case "shallow_merchant": return <Store className="h-3 w-3" />;
      default: return <Users className="h-3 w-3" />;
    }
  };

  const getRoleLabel = (role: string, merchantType?: string | null) => {
    if (role === "shallow_merchant" || (role === "merchant" && merchantType === "shallow")) return "浅层商家";
    switch (role) {
      case "admin": return "Admin";
      case "supervisor": return "Supervisor";
      case "merchant": return "Merchant";
      default: return "User";
    }
  };

  const getEffectiveRole = (user: AdminUser) => {
    if (user.role === "merchant" && user.merchant_type === "shallow") return "shallow_merchant";
    return user.role;
  };

  const formatDate = (dateStr: string | null | undefined) => {
    if (!dateStr) return "-";
    return new Date(dateStr).toLocaleDateString("zh-CN", { month: "2-digit", day: "2-digit", year: "2-digit" });
  };

  const statCards = stats ? [
    { label: t("admin.totalUsersLabel"), value: stats.total, icon: Users, color: "text-primary" },
    { label: "Admin", value: stats.admins, icon: Shield, color: "text-red-500" },
    { label: "Supervisor", value: stats.supervisors, icon: Shield, color: "text-blue-500" },
    { label: t("admin.merchantsLabel"), value: stats.merchants, icon: Briefcase, color: "text-emerald-500" },
    { label: "浅层商家", value: stats.shallowMerchants, icon: Store, color: "text-cyan-500" },
    { label: t("admin.regularUsersLabel"), value: stats.regularUsers, icon: Users, color: "text-muted-foreground" },
  ] : [];

  return (
    <div className="space-y-4 w-full max-w-full">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-primary/10 rounded-lg">
            <UserCog className="h-5 w-5 text-primary" />
          </div>
          <div>
            <h1 className="text-2xl font-bold tracking-tight">{t("admin.userManagement")}</h1>
            <p className="text-sm text-muted-foreground">{t("admin.manageUserRoles")}</p>
          </div>
        </div>
        <div className="flex items-center gap-2">
          {isAdmin && (
            <CreateUserDialog
              trigger={
                <Button variant="default" size="sm">
                  <UserPlus className="mr-1.5 h-4 w-4" />
                  {t("admin.createUser")}
                </Button>
              }
            />
          )}
          <Button variant="outline" size="sm" onClick={handleExport}>
            <Download className="h-4 w-4" />
          </Button>
        </div>
      </div>

      {/* Stats */}
      {!isSupervisor && stats && (
        <div className="grid grid-cols-3 lg:grid-cols-6 gap-2">
          {statCards.map((s) => (
            <button
              key={s.label}
              onClick={() => {
                const filter = s.label === t("admin.totalUsersLabel") ? "all"
                  : s.label === "Admin" ? "admin"
                  : s.label === "Supervisor" ? "supervisor"
                  : s.label === t("admin.merchantsLabel") ? "merchant"
                  : s.label === "浅层商家" ? "shallow_merchant"
                  : "user";
                setRoleFilter(filter);
                setCurrentPage(0);
              }}
              className={`flex items-center gap-2 p-3 rounded-lg border text-left transition-colors ${
                (roleFilter === "all" && s.label === t("admin.totalUsersLabel")) ||
                (roleFilter === "admin" && s.label === "Admin") ||
                (roleFilter === "supervisor" && s.label === "Supervisor") ||
                (roleFilter === "merchant" && s.label === t("admin.merchantsLabel")) ||
                (roleFilter === "shallow_merchant" && s.label === "浅层商家") ||
                (roleFilter === "user" && s.label === t("admin.regularUsersLabel"))
                  ? "border-primary bg-primary/5"
                  : "border-border hover:bg-muted/50"
              }`}
            >
              <s.icon className={`h-4 w-4 ${s.color} flex-shrink-0`} />
              <div className="min-w-0">
                <div className="text-lg font-bold leading-tight">{s.value}</div>
                <div className="text-[10px] text-muted-foreground truncate">{s.label}</div>
              </div>
            </button>
          ))}
        </div>
      )}

      {/* Search & Sort */}
      <div className="flex items-center gap-2 flex-wrap">
        <div className="relative flex-1 min-w-[200px]">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input
            placeholder="搜索用户名、手机号、邮箱..."
            value={searchInput}
            onChange={(e) => setSearchInput(e.target.value)}
            className="pl-9 pr-8 h-9"
          />
          {searchInput && (
            <Button variant="ghost" size="icon" className="absolute right-1 top-1/2 -translate-y-1/2 h-6 w-6" onClick={() => setSearchInput("")}>
              <X className="h-3.5 w-3.5" />
            </Button>
          )}
        </div>
        <Button
          variant="outline" size="sm" className="h-9"
          onClick={() => {
            const newDir = sortDirection === "desc" ? "asc" : "desc";
            setSortDirection(newDir);
            setCurrentPage(0);
          }}
        >
          {sortDirection === "desc" ? <ArrowDown className="h-3.5 w-3.5 mr-1" /> : <ArrowUp className="h-3.5 w-3.5 mr-1" />}
          {sortBy === "name" ? "名称" : "创建"}
        </Button>
        <Select value={sortBy} onValueChange={(v) => { setSortBy(v); setCurrentPage(0); }}>
          <SelectTrigger className="w-[100px] h-9">
            <SelectValue />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="name">按名称</SelectItem>
            <SelectItem value="created">按时间</SelectItem>
          </SelectContent>
        </Select>
      </div>

      {/* Batch Operations */}
      {isAdmin && selectedUsers.length > 0 && (
        <div className="flex items-center gap-3 bg-primary/5 border border-primary/20 rounded-lg px-4 py-2.5">
          <span className="text-sm font-medium">已选 {selectedUsers.length} 项</span>
          <div className="flex gap-2 items-center flex-wrap">
            <Select value={batchRole} onValueChange={setBatchRole}>
              <SelectTrigger className="w-[120px] h-8 text-xs">
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                {availableRoles.map(role => (
                  <SelectItem key={role} value={role}>
                    {getRoleLabel(role)}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
            <Button size="sm" className="h-8 text-xs" onClick={handleBatchChangeRole}>应用角色</Button>
            <Button
              variant="destructive" size="sm" className="h-8 text-xs"
              onClick={() => setBatchDeleteDialog({ open: true, step: 1, confirmText: "" })}
            >
              <Trash2 className="mr-1 h-3.5 w-3.5" />
              删除
            </Button>
            <Button variant="ghost" size="sm" className="h-8 text-xs" onClick={() => setSelectedUsers([])}>
              取消
            </Button>
          </div>
        </div>
      )}

      {/* Table */}
      <div className="rounded-lg border bg-card overflow-hidden">
        <Table className="table-fixed w-full">
          <TableHeader>
            <TableRow className="hover:bg-transparent">
              {isAdmin && (
                <TableHead className="w-8">
                  <Checkbox
                    checked={selectedUsers.length === users.length && users.length > 0}
                    onCheckedChange={toggleSelectAll}
                  />
                </TableHead>
              )}
              <TableHead className="w-10"></TableHead>
              <TableHead className="w-[25%]">用户</TableHead>
              <TableHead className="hidden md:table-cell">联系方式</TableHead>
              <TableHead className="w-24">角色</TableHead>
              <TableHead className="hidden lg:table-cell w-20">积分</TableHead>
              <TableHead className="hidden xl:table-cell w-20">创建</TableHead>
              <TableHead className="hidden xl:table-cell w-20">登录</TableHead>
              <TableHead className="w-16 text-center">状态</TableHead>
              <TableHead className="w-12"></TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {isLoading ? (
              Array.from({ length: 10 }).map((_, i) => (
                <TableRow key={i}>
                  {isAdmin && <TableCell><Skeleton className="h-4 w-4" /></TableCell>}
                  <TableCell><Skeleton className="h-8 w-8 rounded-full" /></TableCell>
                  <TableCell><Skeleton className="h-4 w-24" /></TableCell>
                  <TableCell className="hidden md:table-cell"><Skeleton className="h-4 w-32" /></TableCell>
                  <TableCell><Skeleton className="h-5 w-16" /></TableCell>
                  <TableCell className="hidden lg:table-cell"><Skeleton className="h-4 w-10" /></TableCell>
                  <TableCell className="hidden xl:table-cell"><Skeleton className="h-4 w-14" /></TableCell>
                  <TableCell className="hidden xl:table-cell"><Skeleton className="h-4 w-14" /></TableCell>
                  <TableCell><Skeleton className="h-4 w-8 mx-auto" /></TableCell>
                  <TableCell><Skeleton className="h-6 w-6" /></TableCell>
                </TableRow>
              ))
            ) : users.length === 0 ? (
              <TableRow>
                <TableCell colSpan={10} className="text-center py-16 text-muted-foreground">
                  <Users className="h-10 w-10 mx-auto mb-2 opacity-30" />
                  没有找到匹配的用户
                </TableCell>
              </TableRow>
            ) : (
              users.map((user) => {
                const effectiveRole = getEffectiveRole(user);
                return (
                  <TableRow key={user.id} className="group">
                    {isAdmin && (
                      <TableCell>
                        <Checkbox
                          checked={selectedUsers.includes(user.id)}
                          onCheckedChange={() => toggleSelectUser(user.id)}
                        />
                      </TableCell>
                    )}
                    <TableCell className="p-2">
                      <Avatar className="h-8 w-8">
                        <AvatarImage src={user.avatar_url || ""} />
                        <AvatarFallback className="text-xs bg-primary/10 text-primary">
                          {user.display_name?.charAt(0).toUpperCase() || "U"}
                        </AvatarFallback>
                      </Avatar>
                    </TableCell>
                    <TableCell className="overflow-hidden">
                      <div className="min-w-0">
                        <div className="font-medium truncate flex items-center gap-1.5">
                          {user.display_name}
                          {user.is_banned && (
                            <span className="text-[10px] text-orange-500 font-normal">封禁</span>
                          )}
                        </div>
                        <div className="text-xs text-muted-foreground truncate md:hidden">
                          {user.email || user.phone || "-"}
                        </div>
                      </div>
                    </TableCell>
                    <TableCell className="hidden md:table-cell overflow-hidden">
                      <div className="min-w-0">
                        <div className="text-sm truncate">{user.email || "-"}</div>
                        {user.phone && (
                          <div className="text-xs text-muted-foreground truncate">{user.phone}</div>
                        )}
                      </div>
                    </TableCell>
                    <TableCell>
                      <Badge variant="outline" className={`text-[10px] px-1.5 py-0.5 gap-1 ${getRoleBadgeVariant(effectiveRole, user.merchant_type)}`}>
                        {getRoleIcon(effectiveRole)}
                        {getRoleLabel(user.role, user.merchant_type)}
                      </Badge>
                    </TableCell>
                    <TableCell className="hidden lg:table-cell">
                      <span className="text-sm tabular-nums">{user.points}</span>
                    </TableCell>
                    <TableCell className="hidden xl:table-cell">
                      <span className="text-xs text-muted-foreground">{formatDate(user.auth_created_at || user.created_at)}</span>
                    </TableCell>
                    <TableCell className="hidden xl:table-cell">
                      <span className="text-xs text-muted-foreground">{formatDate(user.last_sign_in_at)}</span>
                    </TableCell>
                    <TableCell className="text-center">
                      {user.is_banned ? (
                        <span className="inline-block h-2 w-2 rounded-full bg-orange-500" title="已封禁" />
                      ) : user.is_muted ? (
                        <span className="inline-block h-2 w-2 rounded-full bg-yellow-500" title="已禁言" />
                      ) : (
                        <span className="inline-block h-2 w-2 rounded-full bg-green-500" title="正常" />
                      )}
                    </TableCell>
                    <TableCell>
                      <DropdownMenu>
                        <DropdownMenuTrigger asChild>
                          <Button variant="ghost" size="icon" className="h-7 w-7 opacity-60 group-hover:opacity-100">
                            <MoreHorizontal className="h-4 w-4" />
                          </Button>
                        </DropdownMenuTrigger>
                        <DropdownMenuContent align="end" className="w-48">
                          <DropdownMenuItem onClick={() => setUserProfileDialog({ open: true, userId: user.id, userName: user.display_name, userRole: user.role })}>
                            <Eye className="mr-2 h-3.5 w-3.5" />
                            查看资料
                          </DropdownMenuItem>
                          <DropdownMenuItem onClick={() => navigate(`/user/${user.id}`)}>
                            <ExternalLink className="mr-2 h-3.5 w-3.5" />
                            查看主页
                          </DropdownMenuItem>

                          {isSupervisor && user.role === "merchant" && (
                            <DropdownMenuItem onClick={() => {
                              // Trigger edit profile dialog through a ref pattern - we use state
                            }}>
                              <Edit className="mr-2 h-3.5 w-3.5" />
                              编辑资料
                            </DropdownMenuItem>
                          )}

                          {(user.role === "merchant" || user.role === "supervisor") && (
                            <DropdownMenuItem onClick={() => setMerchantRestaurantsDialog({
                              open: true,
                              merchantId: user.id,
                              merchantName: user.display_name,
                              userRole: user.role as "merchant" | "supervisor",
                            })}>
                              <Store className="mr-2 h-3.5 w-3.5" />
                              管理餐厅
                            </DropdownMenuItem>
                          )}

                          {isAdmin && (
                            <>
                              <DropdownMenuSeparator />
                              {availableRoles.filter(r => r !== effectiveRole).map(role => (
                                <DropdownMenuItem
                                  key={role}
                                  onClick={() => setRoleChangeDialog({
                                    open: true,
                                    userId: user.id,
                                    userName: user.display_name,
                                    currentRole: effectiveRole,
                                    newRole: role,
                                  })}
                                >
                                  {getRoleIcon(role)}
                                  <span className="ml-2">设为 {getRoleLabel(role)}</span>
                                </DropdownMenuItem>
                              ))}
                            </>
                          )}

                          {isAdmin && user.role === "merchant" && (
                            <>
                              <DropdownMenuSeparator />
                              <DropdownMenuItem onClick={() => {
                                // AssignMerchantToSupervisorDialog - trigger through state
                              }}>
                                <UserCog className="mr-2 h-3.5 w-3.5" />
                                分配主管
                              </DropdownMenuItem>
                            </>
                          )}

                          {isAdmin && user.role === "supervisor" && (
                            <DropdownMenuItem onClick={() => {
                              // AssignMerchantsToSupervisorDialog
                            }}>
                              <Users className="mr-2 h-3.5 w-3.5" />
                              管理商家
                            </DropdownMenuItem>
                          )}

                          {isAdmin && user.role !== "admin" && (
                            <>
                              <DropdownMenuSeparator />
                              <DropdownMenuItem
                                className="text-destructive focus:text-destructive"
                                onClick={() => setDeleteUserDialog({
                                  open: true,
                                  userId: user.id,
                                  userName: user.display_name,
                                  userRole: user.role,
                                })}
                              >
                                <Trash2 className="mr-2 h-3.5 w-3.5" />
                                删除用户
                              </DropdownMenuItem>
                            </>
                          )}
                        </DropdownMenuContent>
                      </DropdownMenu>
                    </TableCell>
                  </TableRow>
                );
              })
            )}
          </TableBody>
        </Table>
      </div>

      {/* Pagination */}
      {totalPages > 1 && (
        <div className="flex items-center justify-between">
          <span className="text-sm text-muted-foreground">
            {startIndex}-{endIndex} / {totalItems.toLocaleString()}
          </span>
          <Pagination>
            <PaginationContent>
              <PaginationItem>
                <PaginationPrevious
                  onClick={() => goToPage(currentPage - 1)}
                  className={currentPage === 0 ? "pointer-events-none opacity-50" : "cursor-pointer"}
                />
              </PaginationItem>
              {Array.from({ length: totalPages }, (_, i) => i).map((page) => {
                if (page === 0 || page === totalPages - 1 || (page >= currentPage - 1 && page <= currentPage + 1)) {
                  return (
                    <PaginationItem key={page}>
                      <PaginationLink onClick={() => goToPage(page)} isActive={currentPage === page} className="cursor-pointer">
                        {page + 1}
                      </PaginationLink>
                    </PaginationItem>
                  );
                }
                if (page === currentPage - 2 || page === currentPage + 2) {
                  return <PaginationItem key={page}><PaginationEllipsis /></PaginationItem>;
                }
                return null;
              })}
              <PaginationItem>
                <PaginationNext
                  onClick={() => goToPage(currentPage + 1)}
                  className={currentPage >= totalPages - 1 ? "pointer-events-none opacity-50" : "cursor-pointer"}
                />
              </PaginationItem>
            </PaginationContent>
          </Pagination>
        </div>
      )}

      {/* Role Change Dialog */}
      <AlertDialog open={roleChangeDialog.open} onOpenChange={(open) => {
        if (!open) setRoleChangeDialog({ open: false, userId: "", userName: "", currentRole: "", newRole: "" });
      }}>
        <AlertDialogContent className="max-w-[90vw] sm:max-w-[500px]">
          <AlertDialogHeader>
            <AlertDialogTitle className="flex items-center gap-2">
              <Shield className="h-5 w-5 text-primary" />
              确认角色更改
            </AlertDialogTitle>
            <AlertDialogDescription className="space-y-4 pt-4">
              <div className="bg-muted/50 p-4 rounded-lg space-y-3">
                <div className="flex items-center justify-between">
                  <span className="text-sm text-muted-foreground">用户：</span>
                  <span className="font-semibold text-foreground">{roleChangeDialog.userName}</span>
                </div>
                <Separator />
                <div className="flex items-center justify-between">
                  <span className="text-sm text-muted-foreground">当前：</span>
                  <Badge variant="outline" className={getRoleBadgeVariant(roleChangeDialog.currentRole)}>
                    {getRoleIcon(roleChangeDialog.currentRole)}
                    <span className="ml-1">{getRoleLabel(roleChangeDialog.currentRole)}</span>
                  </Badge>
                </div>
                <div className="text-center text-xl text-primary">↓</div>
                <div className="flex items-center justify-between">
                  <span className="text-sm text-muted-foreground">新角色：</span>
                  <Badge variant="outline" className={getRoleBadgeVariant(roleChangeDialog.newRole)}>
                    {getRoleIcon(roleChangeDialog.newRole)}
                    <span className="ml-1">{getRoleLabel(roleChangeDialog.newRole)}</span>
                  </Badge>
                </div>
              </div>

              {roleChangeDialog.newRole === "admin" && (
                <div className="bg-destructive/10 border border-destructive/20 p-3 rounded-lg flex gap-2 text-sm">
                  <Shield className="h-4 w-4 text-destructive flex-shrink-0 mt-0.5" />
                  <span>⚠️ 将授予管理员权限，请谨慎操作。</span>
                </div>
              )}
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>取消</AlertDialogCancel>
            <AlertDialogAction onClick={handleChangeRole}>确认更改</AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>

      {/* Merchant Restaurants Dialog */}
      <MerchantRestaurantsDialog
        open={merchantRestaurantsDialog.open}
        onOpenChange={(open) => setMerchantRestaurantsDialog(prev => ({ ...prev, open }))}
        merchantId={merchantRestaurantsDialog.merchantId}
        merchantName={merchantRestaurantsDialog.merchantName}
        userRole={merchantRestaurantsDialog.userRole}
      />

      {/* Delete User Dialog */}
      <DeleteUserDialog
        open={deleteUserDialog.open}
        onOpenChange={(open) => { if (!open) setDeleteUserDialog({ open: false, userId: "", userName: "", userRole: "" }); }}
        userName={deleteUserDialog.userName}
        userId={deleteUserDialog.userId}
        userRole={deleteUserDialog.userRole}
        onConfirm={handleDeleteUser}
        isDeleting={deleteUser.isPending}
      />

      {/* Batch Delete Dialog */}
      <AlertDialog open={batchDeleteDialog.open} onOpenChange={(open) => {
        if (!open) setBatchDeleteDialog({ open: false, step: 1, confirmText: "" });
      }}>
        <AlertDialogContent className="max-w-[90vw] sm:max-w-[500px]">
          {batchDeleteDialog.step === 1 ? (
            <>
              <AlertDialogHeader>
                <AlertDialogTitle className="flex items-center gap-2 text-destructive">
                  <AlertTriangle className="h-5 w-5" />
                  批量删除用户
                </AlertDialogTitle>
                <AlertDialogDescription>
                  <div className="bg-destructive/10 border border-destructive/20 p-4 rounded-lg mt-4">
                    <p className="font-semibold text-foreground">
                      即将删除 {selectedUsers.length} 个用户，此操作不可撤销。
                    </p>
                  </div>
                </AlertDialogDescription>
              </AlertDialogHeader>
              <AlertDialogFooter>
                <AlertDialogCancel>取消</AlertDialogCancel>
                <AlertDialogAction onClick={() => setBatchDeleteDialog(prev => ({ ...prev, step: 2 }))} className="bg-destructive hover:bg-destructive/90">
                  继续
                </AlertDialogAction>
              </AlertDialogFooter>
            </>
          ) : (
            <>
              <AlertDialogHeader>
                <AlertDialogTitle className="flex items-center gap-2 text-destructive">
                  <Trash2 className="h-5 w-5" />
                  最终确认
                </AlertDialogTitle>
                <AlertDialogDescription className="space-y-4 pt-4">
                  <p className="text-foreground font-medium">
                    输入 "DELETE" 确认删除 {selectedUsers.length} 个用户
                  </p>
                  <Input
                    value={batchDeleteDialog.confirmText}
                    onChange={(e) => setBatchDeleteDialog(prev => ({ ...prev, confirmText: e.target.value }))}
                    placeholder="DELETE"
                    className="uppercase"
                    autoComplete="off"
                  />
                </AlertDialogDescription>
              </AlertDialogHeader>
              <AlertDialogFooter>
                <AlertDialogCancel>取消</AlertDialogCancel>
                <AlertDialogAction
                  onClick={handleBatchDeleteConfirm}
                  disabled={batchDeleteDialog.confirmText.toLowerCase() !== "delete" || batchDeleteUsers.isPending}
                  className="bg-destructive hover:bg-destructive/90"
                >
                  {batchDeleteUsers.isPending ? "删除中..." : "确认删除"}
                </AlertDialogAction>
              </AlertDialogFooter>
            </>
          )}
        </AlertDialogContent>
      </AlertDialog>

      {/* User Profile Dialog */}
      <UserProfileDialog
        open={userProfileDialog.open}
        onOpenChange={(open) => setUserProfileDialog(prev => ({ ...prev, open }))}
        userId={userProfileDialog.userId}
        userName={userProfileDialog.userName}
        userRole={userProfileDialog.userRole}
      />
    </div>
  );
};

export default AdminUsers;
