import { useState, useEffect } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useTranslation } from "react-i18next";
import { useLocalizedContent } from "@/hooks/useLocalizedContent";
import { useAuth } from "@/contexts/AuthContext";
import { useUserRole } from "@/hooks/useUserRole";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Checkbox } from "@/components/ui/checkbox";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Loader2, Store, MapPin, Search, User } from "lucide-react";
import { useToast } from "@/hooks/use-toast";
import { ScrollArea } from "@/components/ui/scroll-area";
import {
  Tooltip,
  TooltipContent,
  TooltipProvider,
  TooltipTrigger,
} from "@/components/ui/tooltip";

interface MerchantRestaurantsDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  merchantId: string;
  merchantName: string;
  userRole: "merchant" | "supervisor";
}

const MerchantRestaurantsDialog = ({
  open,
  onOpenChange,
  merchantId,
  merchantName,
  userRole,
}: MerchantRestaurantsDialogProps) => {
  const { t } = useTranslation();
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const { localizeRestaurant } = useLocalizedContent();
  const { user } = useAuth();
  const { isSupervisor } = useUserRole();
  const [selectedRestaurants, setSelectedRestaurants] = useState<string[]>([]);
  const [searchQuery, setSearchQuery] = useState("");

  // Fetch supervisor's restaurants if current user is supervisor
  const { data: supervisorRestaurantIds } = useQuery({
    queryKey: ["supervisorRestaurants", user?.id],
    queryFn: async () => {
      if (!user || !isSupervisor) return null;
      
      const { data, error } = await supabase
        .from("merchant_restaurants")
        .select("restaurant_id")
        .eq("user_id", user.id);
      
      if (error) throw error;
      return data?.map(mr => mr.restaurant_id) || [];
    },
    enabled: open && isSupervisor && !!user,
  });

  // Fetch all restaurants (or filtered by supervisor's restaurants)
  const { data: allRestaurants, isLoading: restaurantsLoading } = useQuery({
    queryKey: ["allRestaurants", supervisorRestaurantIds],
    queryFn: async () => {
      let query = supabase
        .from("restaurants")
        .select("*")
        .order("name");
      
      // If supervisor, only show their managed restaurants
      if (isSupervisor && supervisorRestaurantIds && supervisorRestaurantIds.length > 0) {
        query = query.in("id", supervisorRestaurantIds);
      }
      
      const { data, error } = await query;
      
      if (error) throw error;
      return data;
    },
    enabled: !isSupervisor || (isSupervisor && supervisorRestaurantIds !== undefined),
  });

  // Fetch merchant's current restaurants
  const { data: merchantRestaurants, isLoading: merchantRestaurantsLoading } = useQuery({
    queryKey: ["merchantRestaurants", merchantId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("merchant_restaurants")
        .select("restaurant_id")
        .eq("user_id", merchantId);
      
      if (error) throw error;
      return data?.map(mr => mr.restaurant_id) || [];
    },
    enabled: open,
  });

  // Fetch all restaurant assignments (which accounts are assigned to each restaurant)
  const { data: allAssignments } = useQuery({
    queryKey: ["allRestaurantAssignments"],
    queryFn: async () => {
      // First get all merchant_restaurants records
      const { data: mrData, error: mrError } = await supabase
        .from("merchant_restaurants")
        .select("restaurant_id, user_id");
      
      if (mrError) throw mrError;
      if (!mrData || mrData.length === 0) return {};
      
      // Get unique user IDs
      const userIds = [...new Set(mrData.map(mr => mr.user_id))];
      
      // Fetch profiles for these users
      const { data: profilesData } = await supabase
        .from("profiles")
        .select("id, display_name")
        .in("id", userIds);
      
      // Fetch roles for these users
      const { data: rolesData } = await supabase
        .from("user_roles")
        .select("user_id, role")
        .in("user_id", userIds);
      
      // Create lookup maps
      const profilesMap = new Map(profilesData?.map(p => [p.id, p.display_name]) || []);
      const rolesMap = new Map(rolesData?.map(r => [r.user_id, r.role]) || []);
      
      // Group by restaurant_id
      const assignmentsByRestaurant: Record<string, Array<{ userId: string; displayName: string; role: string }>> = {};
      mrData.forEach((item) => {
        if (!assignmentsByRestaurant[item.restaurant_id]) {
          assignmentsByRestaurant[item.restaurant_id] = [];
        }
        assignmentsByRestaurant[item.restaurant_id].push({
          userId: item.user_id,
          displayName: profilesMap.get(item.user_id) || "Unknown",
          role: rolesMap.get(item.user_id) || "user",
        });
      });
      
      return assignmentsByRestaurant;
    },
    enabled: open,
  });

  // Set selected restaurants when merchant restaurants are loaded
  useEffect(() => {
    if (merchantRestaurants) {
      setSelectedRestaurants(merchantRestaurants);
    }
  }, [merchantRestaurants]);

  // Save changes mutation
  const saveMutation = useMutation({
    mutationFn: async () => {
      // First, delete all existing associations
      const { error: deleteError } = await supabase
        .from("merchant_restaurants")
        .delete()
        .eq("user_id", merchantId);

      if (deleteError) throw deleteError;

      // Then, insert new associations
      if (selectedRestaurants.length > 0) {
        const { error: insertError } = await supabase
          .from("merchant_restaurants")
          .insert(
            selectedRestaurants.map(restaurantId => ({
              user_id: merchantId,
              restaurant_id: restaurantId,
            }))
          );

        if (insertError) throw insertError;
      }
    },
    onSuccess: () => {
      toast({
        title: t("toast.merchantRestaurantsSaved"),
        description: t("toast.merchantRestaurantsDescription"),
      });
      queryClient.invalidateQueries({ queryKey: ["merchantRestaurants"] });
      queryClient.invalidateQueries({ queryKey: ["adminUsers"] });
      onOpenChange(false);
    },
    onError: (error) => {
      console.error("Error saving merchant restaurants:", error);
      toast({
        title: t("toast.merchantRestaurantsSaveFailed"),
        description: t("toast.merchantRestaurantsDescriptionFailed"),
        variant: "destructive",
      });
    },
  });

  const toggleRestaurant = (restaurantId: string) => {
    if (userRole === "merchant") {
      // Merchant can only select one restaurant, but can deselect
      if (selectedRestaurants.includes(restaurantId)) {
        setSelectedRestaurants([]);
      } else {
        setSelectedRestaurants([restaurantId]);
      }
    } else {
      // Supervisor can select multiple restaurants
      setSelectedRestaurants(prev => 
        prev.includes(restaurantId)
          ? prev.filter(id => id !== restaurantId)
          : [...prev, restaurantId]
      );
    }
  };

  const handleSave = () => {
    saveMutation.mutate();
  };

  const isLoading = restaurantsLoading || merchantRestaurantsLoading;

  // Filter restaurants based on search query
  const filteredRestaurants = allRestaurants?.filter((restaurant) => {
    if (!searchQuery.trim()) return true;
    const localizedRest = localizeRestaurant(restaurant);
    return localizedRest.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
           restaurant.address.toLowerCase().includes(searchQuery.toLowerCase());
  });

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-2xl max-h-[80vh] flex flex-col">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <Store className="w-5 h-5" />
            {userRole === "merchant" ? t("merchant.manageRestaurants") : t("merchant.manageSupervisorRestaurants")}
          </DialogTitle>
          <DialogDescription>
            {t("merchant.assignRestaurantsTo", { name: merchantName })}
            {userRole === "merchant" && (
              <span className="block mt-1 text-primary font-medium">
                {t("merchant.merchantOnlyOne")}
              </span>
            )}
            <span className="block mt-1 text-muted-foreground text-xs">
              {t("merchant.saveReminder")}
            </span>
          </DialogDescription>
        </DialogHeader>

        {isLoading ? (
          <div className="flex justify-center py-8">
            <Loader2 className="w-6 h-6 animate-spin text-primary" />
          </div>
        ) : (
          <div className="flex flex-col flex-1 min-h-0">
            <div className="relative mb-4 flex-shrink-0">
              <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-muted-foreground" />
              <Input
                placeholder={t("merchant.searchRestaurants")}
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="pl-9"
              />
            </div>
            <ScrollArea className="flex-1 min-h-0 pr-4">
              <div className="space-y-3">
                {filteredRestaurants?.map((restaurant) => {
                  const isSelected = selectedRestaurants.includes(restaurant.id);
                  const localizedRest = localizeRestaurant(restaurant);
                  const assignedUsers = allAssignments?.[restaurant.id]?.filter(u => u.userId !== merchantId) || [];
                  
                  return (
                    <div
                      key={restaurant.id}
                      className="flex items-start space-x-3 p-4 rounded-lg border hover:bg-accent/50 transition-all cursor-pointer"
                      onClick={() => toggleRestaurant(restaurant.id)}
                    >
                      <Checkbox
                        checked={isSelected}
                        className="mt-1"
                      />
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-2 mb-2 flex-wrap">
                          <p className="text-sm font-medium leading-none">
                            {localizedRest.name}
                          </p>
                          {isSelected && (
                            <Badge variant="secondary" className="text-xs">
                              {t("merchant.selected")}
                            </Badge>
                          )}
                        </div>
                        <div className="flex items-center gap-1 text-xs text-muted-foreground">
                          <MapPin className="w-3 h-3" />
                          <span className="line-clamp-1">{restaurant.address}</span>
                        </div>
                        {restaurant.type && restaurant.type.length > 0 && (
                          <div className="flex gap-1 mt-2 flex-wrap">
                            {restaurant.type.slice(0, 2).map((type, idx) => (
                              <Badge key={idx} variant="outline" className="text-xs">
                                {type}
                              </Badge>
                            ))}
                          </div>
                        )}
                        {/* Display assigned accounts */}
                        {assignedUsers.length > 0 && (
                          <div className="flex items-center gap-1.5 mt-2 flex-wrap">
                            <User className="w-3 h-3 text-muted-foreground" />
                            <span className="text-xs text-muted-foreground">{t("merchant.assignedTo")}:</span>
                            <TooltipProvider>
                              {assignedUsers.slice(0, 3).map((user, idx) => (
                                <Tooltip key={user.userId}>
                                  <TooltipTrigger asChild>
                                    <Badge 
                                      variant="outline" 
                                      className={`text-xs ${
                                        user.role === 'supervisor' 
                                          ? 'border-blue-500/50 text-blue-600 dark:text-blue-400' 
                                          : 'border-amber-500/50 text-amber-600 dark:text-amber-400'
                                      }`}
                                    >
                                      {user.displayName}
                                    </Badge>
                                  </TooltipTrigger>
                                  <TooltipContent>
                                    <p>{user.role === 'supervisor' ? t("roles.supervisor") : t("roles.merchant")}</p>
                                  </TooltipContent>
                                </Tooltip>
                              ))}
                              {assignedUsers.length > 3 && (
                                <Tooltip>
                                  <TooltipTrigger asChild>
                                    <Badge variant="outline" className="text-xs">
                                      +{assignedUsers.length - 3}
                                    </Badge>
                                  </TooltipTrigger>
                                  <TooltipContent>
                                    <div className="space-y-1">
                                      {assignedUsers.slice(3).map(user => (
                                        <p key={user.userId}>{user.displayName} ({user.role === 'supervisor' ? t("roles.supervisor") : t("roles.merchant")})</p>
                                      ))}
                                    </div>
                                  </TooltipContent>
                                </Tooltip>
                              )}
                            </TooltipProvider>
                          </div>
                        )}
                      </div>
                    </div>
                  );
                })}
              </div>
            </ScrollArea>

            <div className="flex items-center justify-between pt-4 border-t flex-shrink-0">
              <div className="text-sm text-muted-foreground">
                {userRole === "merchant" 
                  ? t("merchant.selectedCountOne", { count: selectedRestaurants.length })
                  : t("merchant.selectedCountMulti", { count: selectedRestaurants.length })
                }
              </div>
              <div className="flex gap-2">
                <Button
                  variant="outline"
                  onClick={() => onOpenChange(false)}
                  disabled={saveMutation.isPending}
                >
                  {t("common.cancel")}
                </Button>
                <Button
                  onClick={handleSave}
                  disabled={saveMutation.isPending}
                >
                  {saveMutation.isPending && (
                    <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                  )}
                  {t("common.save")}
                </Button>
              </div>
            </div>
          </div>
        )}
      </DialogContent>
    </Dialog>
  );
};

export default MerchantRestaurantsDialog;
